  ('social-worker-moex-00738', 'social-worker', 'social-worker-moex-112-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據老人福利法規定，有關老人保護安置，下列敘述何者錯誤？', '["老人因直系血親卑親屬疏忽導致其生命發生危難者，縣市政府得依老人之申請予以適當保護及 安置", "有關老人保護及安置費用，老人、配偶或直系血親卑親屬不需支付，由縣市政府全數支付", "老人因依契約負照顧義務之人有虐待導致其自由發生危難者，縣市政府得依職權予以適當保護 及安置", "有關老人保護及安置費用，縣市政府得因老人、配偶或直系血親卑親屬因生活陷於困境無力負 擔予以減輕"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "2833fa197db9", "answer_pdf_sha1": "b2b06e4bb504", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
